-    }
-    RootDemotes.clear();
-    IsTopRoot = false;
-    IsProfitableToDemoteRoot = true;
-
-    if (ExtraBitWidthNodes.empty()) {
-      NodeIdx = VectorizableTree.size();
-    } else {
-      unsigned NewIdx = 0;
-      do {
-        NewIdx = *ExtraBitWidthNodes.begin();
