-      bool IsSigned = any_of(TE->Scalars, [&](Value *R) {
-                        return !isKnownNonNegative(R, SimplifyQuery(*DL));
-                      });
-      MinBWs.try_emplace(TE, MaxBitWidth, IsSigned);
-    }
-  }
-}
