-  SmallVector<Value *, 16> BuildVectorOpds;
-  SmallVector<Value *, 16> BuildVectorInsts;
-  if (!findBuildAggregate(IVI, TTI, BuildVectorOpds, BuildVectorInsts, R))
-    return false;
