-    }
-
-    if (Incoming.size() <= 1)
-      break;
-
-    // Find the corresponding non-phi nodes for better matching when trying to
-    // build the tree.
-    for (Value *V : Incoming) {
-      SmallVectorImpl<Value *> &Opcodes =
-          PHIToOpcodes.try_emplace(V).first->getSecond();
-      if (!Opcodes.empty())
-        continue;
-      SmallVector<Value *, 4> Nodes(1, V);
