-          if (Res && R.isDeleted(P)) {
-            It = BB->begin();
-            E = BB->end();
-            break;
-          }
-        }
-      }
-      continue;
-    }
-
-    if (HasNoUsers(&*It)) {
-      bool OpsChanged = false;
-      auto *SI = dyn_cast<StoreInst>(It);
-      bool TryToVectorizeRoot = ShouldStartVectorizeHorAtStore || !SI;
-      if (SI) {
-        auto *I = Stores.find(getUnderlyingObject(SI->getPointerOperand()));
