-bool SLPVectorizerPass::vectorizeInsertValueInst(InsertValueInst *IVI,
-                                                 BasicBlock *BB, BoUpSLP &R,
-                                                 bool MaxVFOnly) {
-  if (!R.canMapToVector(IVI->getType()))
-    return false;
