-            StartIdx = std::distance(
-                RangeSizes.begin(),
-                find_if(RangeSizes.drop_front(Sz),
-                        std::bind(IsNotVectorized, Size >= MaxRegVF,
-                                  std::placeholders::_1)));
-          }
-          if (!AnyProfitableGraph && Size >= MaxRegVF && has_single_bit(Size))
