-    for (auto [Idx, Data] : enumerate(Set)) {
-      if (Operands.empty() || Data.second - PrevDist == 1) {
-        Operands.push_back(Stores[Data.first]);
-        PrevDist = Data.second;
-        if (Idx != Set.size() - 1)
-          continue;
-      }
-      auto E = make_scope_exit([&, &DataVar = Data]() {
-        Operands.clear();
